-- View
CREATE OR REPLACE VIEW SANDRA.AVAILABLE_PLAYERS_VW ( activity_ID, activity_date, name, last_name, facr_id, position_ID ) AS
SELECT 
    a.activity_ID,
    a.date_time AS activity_date,
    m.name, 
    m.last_name, 
    p.facr_id,
    p.position_ID
FROM SANDRA.ACTIVITIES a
JOIN SANDRA.PLAYERS p ON 1=1
JOIN SANDRA.TEAM_MEMBERS m ON m.member_ID = p.member_ID
WHERE m.is_active = 'Yes'
  AND NOT EXISTS (
      SELECT 1
      FROM SANDRA.INJURIES i
      WHERE i.player_member_ID = p.member_ID
        AND a.date_time >= i.date_from
        AND a.date_time < NVL(i.date_to, DATE '9999-12-31') + 1
  ) 
;

