-- Custom trigger for injury
CREATE OR REPLACE TRIGGER SANDRA.trg_auto_excuse_injury
BEFORE INSERT ON SANDRA.PERFORMANCES
FOR EACH ROW
DECLARE
    v_activity_date   DATE;
    v_injury_reason   VARCHAR2(255);
BEGIN
    BEGIN
        SELECT date_time INTO v_activity_date FROM SANDRA.ACTIVITIES WHERE activity_ID = :NEW.activity_ID;
    EXCEPTION WHEN NO_DATA_FOUND THEN
        RAISE_APPLICATION_ERROR(-20001, 'Chyba: Aktivita ID ' || :NEW.activity_ID || ' neexistuje.');
    END;

    BEGIN
        SELECT reason INTO v_injury_reason FROM SANDRA.INJURIES WHERE player_member_ID = :NEW.player_member_ID
          AND v_activity_date >= date_from AND v_activity_date < NVL(date_to, DATE '9999-12-31') + 1 AND ROWNUM = 1;
        :NEW.status := 'Excused';
        :NEW.coach_note := 'Auto-omluva: Zranění (' || v_injury_reason || ').';
    EXCEPTION WHEN NO_DATA_FOUND THEN NULL; 
    END;
END;
/